const fs = require('fs');
const path = '/Users/orion/Documents/大都会-通联';
const items = fs.readdirSync(items, { withFileTypes: true });
items.forEach(item => {
  const fullPath = path + '/' + item.name;
  const stat = fs.statSync(fullPath);
  console.log(`${item.isDirectory() ? '[目录]' : '[文件]'} ${item.name} (${(stat.size/1024).toFixed(1)} KB)`);
});

